    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    if not isinstance(expr, str):
        return ""

    # Remove whitespace
    expr = expr.strip()

    if not expr:
        return ""

    # Validate that expression only contains safe characters
    # Allow digits, operators (+, -, *, /, //, %, **), parentheses, and decimal points
    allowed_chars = set("0123456789+-*/%().e ")
    if not all(c in allowed_chars for c in expr):
        return ""

    try:
        import ast
        import operator

        # Parse the expression as an AST
        tree = ast.parse(expr, mode='eval')

        # Validate that only safe node types are used
        for node in ast.walk(tree):
            if isinstance(node, ast.Call):
                # Disallow function calls
                return ""
            if isinstance(node, ast.Attribute):
                # Disallow attribute access
                return ""
            if isinstance(node, ast.Name):
                # Disallow variable names (except built-in constants)
                if node.id not in ('True', 'False', 'None'):
                    return ""

        # Safely evaluate the expression using a restricted evaluator
        result = _safe_eval(tree.body)

        # Convert result to string
        return str(result)

    except (SyntaxError, ValueError, TypeError, ZeroDivisionError, 
