        # Whitelist of allowed commands for security
        allowed_commands = {
            'ls', 'pwd', 'echo', 'cat', 'date', 'whoami', 'id', 'uname',
            'grep', 'find', 'wc', 'head', 'tail', 'sort', 'uniq'
        }

        if args[0] not in allowed_commands:
            print(f"Error: Command '{args[0]}' is not allowed")
            return

